// এলিমেন্ট সিলেক্ট করা
const title = document.querySelector("h1");
const allButtons = document.querySelectorAll("button");

// কনটেন্ট পরিবর্তন করা
title.textContent = "নতুন শিরোনাম";
title.style.color = "green";

// নতুন এলিমেন্ট তৈরি করা
const newPara = document.createElement("p");
newPara.textContent = "এটি নতুন প্যারাগ্রাফ";
document.body.appendChild(newPara);

const btn = document.querySelector("#myButton");

btn.addEventListener("click", function () {
  alert("বাটনে ক্লিক করা হয়েছে!");
});

document.querySelector("#myInput").addEventListener("keyup", (e) => {
  console.log("টাইপ করছেন:", e.target.value);
});
